#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e4+5;
int n,m,Cnt,id[N],f[N],Q;
int Now,bel[N],dep[N],fa[N][20];bool flag[N];
vector<int> g[N],E[N];stack<int> st;
int min(int x,int y){return (x<y?x:y);}
int max(int x,int y){return (x>y?x:y);}
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Tarjan(int u,int Lst){
    id[u]=++Cnt,f[u]=Cnt,st.push(u);
    for(int v:g[u]){
        if(v==Lst)continue;
        if(id[v]==-1)Tarjan(v,u),f[u]=min(f[u],f[v]);
        else f[u]=min(f[u],id[v]);
    }
    if(id[u]==f[u]){
        ++Now,bel[u]=Now;
        while(st.top()!=u)bel[st.top()]=Now,st.pop();st.pop();
    }
    return;
}
void DFS(int u,int Fath){
    if(flag[u])return;flag[u]=1;
    dep[u]=dep[Fath]+1,fa[u][0]=Fath;
    for(int i=0;fa[u][i];i++)fa[u][i+1]=fa[fa[u][i]][i];
    for(int v:E[u])if(v^Fath)DFS(v,u);return;
}
int LCA(int u,int v){
    if(dep[u]<dep[v])swap(u,v);
    for(int i=15;i>=0;i--)
        if(dep[fa[u][i]]>=dep[v])u=fa[u][i];
    if(u==v)return u;
    for(int i=15;i>=0;i--)
        if(fa[u][i]!=fa[v][i])u=fa[u][i],v=fa[v][i];
    return fa[u][0];
}
int Road(int u,int v){return dep[u]+dep[v]-2*dep[LCA(u,v)]+1;}
void B(int u){string s="";while(u)s=(char)(u%2+'0')+s,u>>=1;cout<<s<<"\n";}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++){int x=read(),y=read();g[x].pb(y),g[y].pb(x);}
    memset(f,-1,sizeof(f));memset(id,-1,sizeof(id));
    for(int i=1;i<=n;i++)if(id[i]==-1)Tarjan(i,0);
    for(int u=1;u<=n;u++)for(int v:g[u])
        if(bel[u]!=bel[v])E[bel[v]].pb(bel[u]);
    for(int i=1;i<=Now;i++)if(!flag[bel[i]])DFS(bel[i],0);
    Q=read();while(Q--)B(Road(bel[read()],bel[read()]));
    return 0;
}
